// Accessor for the AST-extracted prop data (generated by scripts/extract-props.mjs,
// run via `pnpm gen:props`). Pages keep their curated prop list + descriptions;
// the type, required, default and source location come from here so they can't
// drift from the real source.

import generated from '@/generated/props.json'

export interface GeneratedProp {
  name: string
  type: string
  required?: boolean
  default?: string
  description?: string
  source?: { path: string; line: number }
}

const DATA = generated as unknown as Record<string, GeneratedProp[]>

export function getGeneratedProps(slug: string): Map<string, GeneratedProp> {
  const rows = DATA[slug] ?? []
  return new Map(rows.map((row) => [row.name, row]))
}

export function propSourceUrl(source: { path: string; line: number }): string {
  return `https://github.com/polarsource/polar/blob/main/${source.path}#L${source.line}`
}
